# Array Replace K

## 问题描述

实现一个函数，输入长度为 `n` 的整数数组 `a`、整数 `old_k` 和 `new_k`，把数组中所有等于 `old_k` 的元素替换成 `new_k`。

约定：

- `n >= 0`
- 数组长度恰好是 `n`
- 需要原地修改数组

## 正确代码

```c
void array_replace_k(int n, int *a, int old_k, int new_k) {
    int i;

    for (i = 0; i < n; ++i) {
        if (a[i] == old_k) {
            a[i] = new_k;
        }
    }
}
```

## 说明

这道题适合验证“条件式原地更新”模式：

- 不是每轮都写
- 更新逻辑取决于当前元素是否命中

#include "../../verification_stdlib.h"
#include "../../verification_list.h"
#include "../../int_array_def.h"

/*@ Extern Coq (count_equal_to_k_spec : list Z -> Z -> Z) */
/*@ Import Coq Require Import count_equal_to_k */

int count_equal_to_k(int n, int *a, int k)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      __return == count_equal_to_k_spec(l, k) &&
      IntArray::full(a, n, l)
*/
{
    int i;
    int ret = 0;

    for (i = 0; i < n; ++i) {
        if (a[i] == k) {
            ret++;
        }
    }

    return ret;
}

#include "../../verification_stdlib.h"
#include "../../verification_list.h"
#include "../../int_array_def.h"

void copy_array(int n, int *src, int *dst)
/*@ With ls ld
    Require
      0 <= n &&
      Zlength(ls) == n &&
      Zlength(ld) == n &&
      IntArray::full(src, n, ls) *
      IntArray::full(dst, n, ld)
    Ensure
      IntArray::full(src, n, ls) *
      IntArray::full(dst, n, ls)
*/
{
    int i;

    for (i = 0; i < n; ++i) {
        dst[i] = src[i];
    }
}

#include "../../verification_stdlib.h"
#include "../../verification_list.h"
#include "../../int_array_def.h"

void array_increment(int n, int *a)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      (forall (i: Z), (0 <= i && i < n) => l[i] < 2147483647) &&
      IntArray::full(a, n, l)
    Ensure
      exists l0,
        Zlength(l0) == n &&
        (forall (i: Z), (0 <= i && i < n) => l0[i] == l[i] + 1) &&
        IntArray::full(a, n, l0)
*/
{
    int i;

    for (i = 0; i < n; ++i) {
        a[i] = a[i] + 1;
    }
}

#include "../../verification_stdlib.h"
#include "../../verification_list.h"
#include "../../int_array_def.h"

void array_add(int n, int *a, int *b, int *out)
/*@ With la, lb, lo
    Require
      0 <= n &&
      Zlength(la) == n &&
      Zlength(lb) == n &&
      Zlength(lo) == n &&
      (forall (i: Z),
        (0 <= i && i < n) =>
        (-2147483648 <= la[i] + lb[i] && la[i] + lb[i] <= 2147483647)) &&
      IntArray::full(a, n, la) *
      IntArray::full(b, n, lb) *
      IntArray::full(out, n, lo)
    Ensure
      exists lr,
        Zlength(lr) == n &&
        (forall (i: Z), (0 <= i && i < n) => lr[i] == la[i] + lb[i]) &&
        IntArray::full(a, n, la) *
        IntArray::full(b, n, lb) *
        IntArray::full(out, n, lr)
*/
{
    int i;

    for (i = 0; i < n; ++i) {
        out[i] = a[i] + b[i];
    }
}

#include "../../verification_stdlib.h"
#include "../../verification_list.h"
#include "../../int_array_def.h"

void array_init(int n, int *a)
/*@ With l
    Require
      0 <= n && IntArray::full(a, n, l)
    Ensure
      IntArray::full(a, n, zeros(n))
*/
{
    int i;

    for (i = 0; i < n; ++i) {
        a[i] = 0;
    }
}

#include "../../verification_stdlib.h"
#include "../../verification_list.h"
#include "../../int_array_def.h"

void array_replace_k(int n, int *a, int old_k, int new_k)
/*@ With l
    Require
      0 <= n &&
      Zlength(l) == n &&
      IntArray::full(a, n, l)
    Ensure
      exists l0,
        Zlength(l0) == n &&
        (forall (i: Z),
          (0 <= i && i < n) =>
          ((l[i] == old_k => l0[i] == new_k) &&
           (l[i] != old_k => l0[i] == l[i]))) &&
        IntArray::full(a, n, l0)
*/
{
    int i;

    for (i = 0; i < n; ++i) {
        if (a[i] == old_k) {
            a[i] = new_k;
        }
    }
}
